UPDATE b_board_column_data
SET		  BD_MN_KEYNO		=	#{MN_KEYNO}
		, BD_BT_KEYNO		=	#{BT_KEYNO}
WHERE	  BD_BN_KEYNO		=	#{BN_KEYNO}

UPDATE b_board_column_data
SET		  BD_MN_KEYNO		=	#{MN_KEYNO}
		, BD_BT_KEYNO		=	#{BT_KEYNO}
		, BD_BL_KEYNO		=	(
									SELECT 	BL_KEYNO 
									FROM b_board_column 
									WHERE 	BL_BT_KEYNO	=	#{BT_KEYNO}
									AND		BL_TYPE		=	'SC_HBHNH'
								)
WHERE	  BD_BN_KEYNO		=	#{BN_KEYNO}
AND		  BD_BL_TYPE		=	'SC_HBHNH'
